import { describe, expect, test } from '@a0n/gnosis/test';

import {
  bundleSkyrmsWithForrestWalk,
  concatForrestWalks,
  encodeHardAssignmentAsForrestWalk,
  forrestWalkFromSkyrmsIterationSnapshots,
  isValidForrestWalkStep,
} from './forrest-skyrms-bridge';
import type { CompilerName } from './types';
import type { SkyrmsIterationSnapshot, SkyrmsResult } from './skyrms-walk';

function twelveNodes(prefix: string): string[] {
  return Array.from({ length: 12 }, (_, i) => `${prefix}${i}`);
}

describe('forrest-skyrms-bridge', () => {
  test('isValidForrestWalkStep accepts strict ascending pairs in range', () => {
    expect(isValidForrestWalkStep({ lo: 0, hi: 11 })).toBe(true);
    expect(isValidForrestWalkStep({ lo: 5, hi: 5 })).toBe(false);
    expect(isValidForrestWalkStep({ lo: 11, hi: 3 })).toBe(false);
    expect(isValidForrestWalkStep({ lo: -1, hi: 3 })).toBe(false);
    expect(isValidForrestWalkStep({ lo: 1.5, hi: 3 })).toBe(false);
  });

  test('encodeHardAssignmentAsForrestWalk is empty when all winners agree', () => {
    const nodes = twelveNodes('n');
    const hard = new Map<string, CompilerName>(
      nodes.map((id) => [id, 'betty' as CompilerName])
    );
    expect(encodeHardAssignmentAsForrestWalk(hard, nodes)).toEqual([]);
  });

  test('encodeHardAssignmentAsForrestWalk emits lex chord when only slots 0 and 11 differ', () => {
    const nodes = twelveNodes('n');
    const hard = new Map<string, CompilerName>(
      nodes.map((id) => [id, 'betty' as CompilerName])
    );
    hard.set(nodes[0]!, 'betti');
    const steps = encodeHardAssignmentAsForrestWalk(hard, nodes);
    expect(steps[0]).toEqual({ lo: 0, hi: 1 });
    expect(steps[steps.length - 1]).toEqual({ lo: 0, hi: 11 });
    expect(steps.length).toBe(11);
  });

  test('encodeHardAssignmentAsForrestWalk rejects wrong slot list length', () => {
    const hard = new Map<string, CompilerName>([['only', 'betty']]);
    expect(() =>
      encodeHardAssignmentAsForrestWalk(hard, ['only'])
    ).toThrow(/exactly 12/);
  });

  test('forrestWalkFromSkyrmsIterationSnapshots concatenates snapshot encodings', () => {
    const nodes = twelveNodes('n');
    const mkSnap = (
      iter: number,
      flipEdge: boolean
    ): SkyrmsIterationSnapshot => {
      const hard = new Map<string, CompilerName>(
        nodes.map((id) => [id, 'betty' as CompilerName])
      );
      if (flipEdge) {
        hard.set(nodes[0]!, 'betti');
      }
      return {
        iteration: iter,
        maxChange: 0.1,
        distributions: new Map(),
        hardAssignment: hard,
      };
    };
    const walk = forrestWalkFromSkyrmsIterationSnapshots(
      [mkSnap(0, false), mkSnap(1, true)],
      nodes
    );
    expect(walk.length).toBe(11);
    expect(walk[0]).toEqual({ lo: 0, hi: 1 });
  });

  test('bundleSkyrmsWithForrestWalk uses final hardAssignment', () => {
    const nodes = twelveNodes('n');
    const hardAssignment = new Map<string, CompilerName>(
      nodes.map((id) => [id, 'betty' as CompilerName])
    );
    hardAssignment.set(nodes[3]!, 'rust');
    const skyrms = {
      assignments: [],
      converged: true,
      iterations: 1,
      hardAssignment,
      diversity: 2,
      totalBoundary: { counts: [], totalEntries: 0 },
      ranking: [],
    } as unknown as SkyrmsResult;

    const bundled = bundleSkyrmsWithForrestWalk(skyrms, nodes);
    expect(bundled.skyrms).toBe(skyrms);
    expect(bundled.forrestWalk.length).toBeGreaterThan(0);
    expect(bundled.forrestWalk.every(isValidForrestWalkStep)).toBe(true);
  });

  test('concatForrestWalks flattens chunks', () => {
    expect(
      concatForrestWalks([
        [
          { lo: 0, hi: 1 },
          { lo: 0, hi: 2 },
        ],
        [{ lo: 1, hi: 2 }],
      ])
    ).toEqual([
      { lo: 0, hi: 1 },
      { lo: 0, hi: 2 },
      { lo: 1, hi: 2 },
    ]);
  });
});
